import{_ as e,o as a,c as o,a2 as i}from"./chunks/framework.BvGAuttJ.js";const h=JSON.parse('{"title":"System Integration","description":"","frontmatter":{},"headers":[],"relativePath":"guide/system.md","filePath":"guide/system.md"}'),r={name:"guide/system.md"};function s(d,t,n,l,c,p){return a(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="system-integration" tabindex="-1">System Integration <a class="header-anchor" href="#system-integration" aria-label="Permalink to &quot;System Integration&quot;">​</a></h1><h2 id="system-tray" tabindex="-1">System Tray <a class="header-anchor" href="#system-tray" aria-label="Permalink to &quot;System Tray&quot;">​</a></h2><p>Alpaka Desktop runs in the system tray when minimised. The tray icon gives you quick access to:</p><ul><li>Open / show the main window</li><li>Quit</li></ul><p>The tray icon works with KDE Plasma (SNI protocol), GNOME (via AppIndicator extension), and Hyprland / other compositors that support the StatusNotifierItem protocol.</p><h2 id="desktop-notifications" tabindex="-1">Desktop Notifications <a class="header-anchor" href="#desktop-notifications" aria-label="Permalink to &quot;Desktop Notifications&quot;">​</a></h2><p>Alpaka Desktop sends desktop notifications via D-Bus (<code>org.freedesktop.Notifications</code>) for various background events, including:</p><ul><li>Model pull complete</li><li>Custom model creation complete</li><li>Background task completion</li><li>Generation or connection errors</li></ul><p>Notifications appear in your desktop notification centre (KDE, GNOME, dunst, etc.).</p><h2 id="ollama-service-control" tabindex="-1">Ollama Service Control <a class="header-anchor" href="#ollama-service-control" aria-label="Permalink to &quot;Ollama Service Control&quot;">​</a></h2><p>If Ollama is installed as a systemd user service (the default for the official Linux installer), Alpaka Desktop will automatically restart the service when you change the models storage path in <strong>Settings → Engine</strong>.</p><p>If Ollama is installed as a system service (root), a <code>pkexec</code> policy kit prompt appears to authorise the restart action.</p><h2 id="compact-twm-mode" tabindex="-1">Compact / TWM Mode <a class="header-anchor" href="#compact-twm-mode" aria-label="Permalink to &quot;Compact / TWM Mode&quot;">​</a></h2><p>Designed for tiling window managers (Hyprland, Sway, i3, bspwm):</p><table tabindex="0"><thead><tr><th>Property</th><th>Standard</th><th>Compact</th></tr></thead><tbody><tr><td>Sidebar</td><td>Visible (260px)</td><td>Hidden</td></tr><tr><td>Message padding</td><td>16px</td><td>8px</td></tr><tr><td>Top bar</td><td>Full controls</td><td>Model name + host dot only</td></tr><tr><td>Font sizes</td><td>15px body</td><td>13px body</td></tr><tr><td>Minimum usable width</td><td>~500px</td><td>~320px</td></tr></tbody></table><p>Toggle with <code>Ctrl+Shift+M</code> or via <strong>Settings → Appearance → Compact Mode</strong>.</p><h2 id="dark-light-mode" tabindex="-1">Dark / Light Mode <a class="header-anchor" href="#dark-light-mode" aria-label="Permalink to &quot;Dark / Light Mode&quot;">​</a></h2><p>Alpaka Desktop defaults to dark mode and follows <code>prefers-color-scheme</code>. Toggle manually via the theme button in the top bar.</p>',18)])])}const u=e(r,[["render",s]]);export{h as __pageData,u as default};
